CREATE VIEW "public"."active_projects" AS (select "id", "name", "description", "asr_config", "accept_voice", "generate_voice", "storage_config", "moderation_config", "cost_management_config", "constants", "metadata", "timezone", "language_code", "auto_create_users", "user_profile_variable_descriptors", "default_guardrail_classifier_id", "sample_copy_config", "starting_stage_id", "conversation_timeout_seconds", "version", "created_at", "updated_at", "archived_at", "archived_by" from "projects" where "projects"."archived_at" is null);--> statement-breakpoint
